const crypto=require("crypto"),store=new Map;function now(){return Date.now()}function create(e,t=6048e5){const r=crypto.randomBytes(32).toString("hex");return store.set(r,{userId:String(e),expiresAt:now()+t}),r}function getUserId(e){if(!e)return null;const t=store.get(e);return t?t.expiresAt<now()?(store.delete(e),null):t.userId:null}function destroy(e){e&&store.delete(e)}function parseTokenFromReq(e,t=process.env.AUTH_TOKEN_NAME||"auth_token"){const r=e.headers.authorization;if(r&&"string"==typeof r){const e=r.match(/^Bearer\s+(.+)$/i);if(e)return e[1]}const o=e.headers.cookie;if(!o||"string"!=typeof o)return null;const n=o.split(";").map((e=>e.trim()));for(const e of n){const r=e.indexOf("=");if(r>0){if(decodeURIComponent(e.slice(0,r))===t)return decodeURIComponent(e.slice(r+1))}}return null}module.exports={create:create,getUserId:getUserId,destroy:destroy,parseTokenFromReq:parseTokenFromReq};